-- create "payments" table
CREATE TABLE "payments" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "provider" character varying(32) NOT NULL, "provider_reference" character varying(191) NOT NULL, "amount" bigint NOT NULL, "currency" character varying(3) NOT NULL, "status" smallint NOT NULL DEFAULT 0, "shop_id" bigint NOT NULL, "order_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "payments_orders_order" FOREIGN KEY ("order_id") REFERENCES "orders" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "payments_shops_shop" FOREIGN KEY ("shop_id") REFERENCES "shops" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "payments_amount_check" CHECK (amount > 0), CONSTRAINT "payments_status_check" CHECK (status = ANY (ARRAY[0, 1, 2, 3])));
-- create index "payment_provider_provider_reference" to table: "payments"
CREATE UNIQUE INDEX "payment_provider_provider_reference" ON "payments" ("provider", "provider_reference");
-- create index "payment_shop_id_order_id" to table: "payments"
CREATE INDEX "payment_shop_id_order_id" ON "payments" ("shop_id", "order_id");
